const fs = require\('fs'\);
const cssContent = fs.readFileSync\('C:/Users/anast/Documents/GitHub/AuthorFunctionSlides/css/rooms.css', 'utf8'\);
// Extract all .room-X classes \(first level, not descendants\)
const defined = [];
const re = /^\\.room-\([a-z0-9-]+\)\\s*[\\{\\.]/gm;
let m;
while \(\(m = re.exec\(cssContent\)\) !== null\) {
  if \(!defined.includes\(m[1]\)\) defined.push\(m[1]\);
}
console.log\('CSS room classes defined:', defined.sort\(\).join\(', '\)\);

// Now check templates
const templates = 'arcade,archive,computer-lab,dark-room,data-center,gallery,game-room,hallway,kitchen,laboratory,lecture-hall,library,observatory,office,ruins,ship-corridor,study,title,typing-office,workshop'.split\(','\);
const missing = templates.filter\(t => !defined.includes\(t\)\);
console.log\('Templates with no CSS class:', missing.length ? missing.join\(', '\) : 'all present'\);
")

